BEGIN TRANSACTION;

drop schema if exists "spedizioni" cascade;

create schema "spedizioni";
set search_path to "spedizioni";

CREATE TABLE SOGGETTO (
    CodiceSogg VARCHAR(50) PRIMARY KEY,
    Nome VARCHAR(255),
    Indirizzo VARCHAR(255)
);

CREATE TABLE CATEGORIA (
    CodiceCat VARCHAR(50) PRIMARY KEY,
    Descrizione VARCHAR(50),
    Prezzo DECIMAL(10,2)
);

CREATE TABLE SPEDIZIONE (
    CodiceSp VARCHAR(50) PRIMARY KEY,
    Mittente VARCHAR(50) REFERENCES SOGGETTO(CodiceSogg),
    Destinatario VARCHAR(50) REFERENCES SOGGETTO(CodiceSogg),
    IndirizzoSpedizione VARCHAR(255),
    CodiceCat VARCHAR(50) REFERENCES CATEGORIA(CodiceCat),
    Stato VARCHAR(50)
);

CREATE TABLE PACCO (
    CodiceSp VARCHAR(50) REFERENCES SPEDIZIONE(CodiceSp),
    NumPacco INTEGER,
    Peso DECIMAL(10,3),
    PRIMARY KEY (CodiceSp, NumPacco)
);

CREATE TABLE LUOGO (
    Coordinate VARCHAR(100) PRIMARY KEY,
    Descrizione VARCHAR(255)
);

CREATE TABLE POSIZIONE (
    CodiceSp VARCHAR(50) REFERENCES SPEDIZIONE(CodiceSp),
    Coordinate VARCHAR(100) REFERENCES LUOGO(Coordinate),
    DataOra TIMESTAMP,
    PRIMARY KEY (CodiceSp, Coordinate)
);

-- No INSERT statements (exam PDF source, no data instances provided)
-- Note: Stato values are: consegnata, rifiutata, in viaggio
-- Note: Categoria Descrizione values are: standard, fast, express
-- Note: IndirizzoSpedizione is optional (NULL means deliver to Destinatario address)

COMMIT;
